queries.sparql:
PREFIX : <http://ambrosia.example.org/journalism#>
PREFIX p: <http://ambrosia.example.org/journalism/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?o0 WHERE {
  {
    ?press_conferences a :Press_Conferences .
    ?press_conferences p:Title ?title .
    BIND(?title AS ?o0)
  }
  UNION
  {
    ?interviews a :Interviews .
    ?interviews p:Title ?title .
    ?interviews p:Participant_Type ?participant_type_f .
    FILTER(STR(?participant_type_f) = "Politician")
    BIND(?title AS ?o0)
  }
}

